class SyncJob
{
    void Run(BlogContext context)
    {
        var blogs = context.Blogs.ToList();
        foreach (var b in blogs) { b.Name = b.Name.Trim(); }

        // EF 9 Cosmos provider now uses patch-based (partial) updates by
        // default, which can fail on older documents missing the expected
        // __jObject shape. If that happens, opt into full-document replace
        // mode via context configuration or per-save behavior.
        context.SaveChanges();
    }
}

